// ─── Day/Days label helper ───────────────────────────────────────────────────
export function fmtDays(n: number): string {
  const v = Number.isInteger(n) ? `${n}` : n.toFixed(1);
  return `${v} ${Math.abs(n) === 1 ? "Day" : "Days"}`;
}

